select
id, scheduled_time, is_deleted, create_user, update_user, create_time, update_time, status
from scheduled_domain_locking_time

    1 = 1 and is_deleted = 0

        and id = #{id}


        and scheduled_time = #{scheduledTime}


        and is_deleted = #{isDeleted}


        and create_user = #{createUser}


        and update_user = #{updateUser}


        and create_time = #{createTime}


        and update_time = #{updateTime}


        and status = #{status}

